#include "JsonCatalogProvider.h"
namespace referencelab { std::vector<ReferenceMetadata> JsonCatalogProvider::scan(const juce::File&f,bool,juce::String&w){std::vector<ReferenceMetadata>out;if(!f.existsAsFile()){w="Catalogo JSON non trovato";return out;}auto parsed=juce::JSON::parse(f.loadFileAsString());auto*a=parsed.getArray();if(!a&&parsed.getDynamicObject())a=parsed.getProperty("references",{}).getArray();if(!a){w="Il catalogo deve contenere un array 'references'";return out;}for(auto&v:*a){juce::String e;auto item=ReferenceMetadata::fromVar(v,e);if(item){item->provider=id();out.push_back(std::move(*item));}else w+=(w.isEmpty()?"":"\n")+e;}return out;} }
